   414→/*
   415→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   416→%                                                                             %
   417→%                                                                             %
   418→%                                                                             %
   419→+   G a u s s J o r d a n E l i m i n a t i o n                               %
   420→%                                                                             %
   421→%                                                                             %
   422→%                                                                             %
   423→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   424→%
   425→%  GaussJordanElimination() returns a matrix in reduced row echelon form,
   426→%  while simultaneously reducing and thus solving the augumented results
   427→%  matrix.
   428→%
   429→%  See also  http://en.wikipedia.org/wiki/Gauss-Jordan_elimination
   430→%
   431→%  The format of the GaussJordanElimination method is:
   432→%
   433→%      MagickBooleanType GaussJordanElimination(double **matrix,
   434→%        double **vectors,const size_t rank,const size_t number_vectors)
   435→%
   436→%  A description of each parameter follows:
   437→%
   438→%    o matrix: the matrix to be reduced, as an 'array of row pointers'.
   439→%
   440→%    o vectors: the additional matrix argumenting the matrix for row reduction.
   441→%             Producing an 'array of column vectors'.
   442→%
   443→%    o rank:  The size of the matrix (both rows and columns).
   444→%             Also represents the number terms that need to be solved.
   445→%
   446→%    o number_vectors: Number of vectors columns, argumenting the above matrix.
   447→%             Usally 1, but can be more for more complex equation solving.
   448→%
   449→%  Note that the 'matrix' is given as a 'array of row pointers' of rank size.
   450→%  That is values can be assigned as   matrix[row][column]   where 'row' is
   451→%  typically the equation, and 'column' is the term of the equation.
   452→%  That is the matrix is in the form of a 'row first array'.
   453→%
   454→%  However 'vectors' is a 'array of column pointers' which can have any number
   455→%  of columns, with each column array the same 'rank' size as 'matrix'.
   456→%
   457→%  This allows for simpler handling of the results, especially is only one
   458→%  column 'vector' is all that is required to produce the desired solution.
   459→%
   460→%  For example, the 'vectors' can consist of a pointer to a simple array of
   461→%  doubles.  when only one set of simultanious equations is to be solved from
   462→%  the given set of coefficient weighted terms.
   463→%
   464→%     double **matrix = AcquireMagickMatrix(8UL,8UL);
   465→%     double coefficents[8];
   466→%     ...
   467→%     GaussJordanElimination(matrix, &coefficents, 8UL, 1UL);
   468→%
   469→%  However by specifing more 'columns' (as an 'array of vector columns',
   470→%  you can use this function to solve a set of 'separable' equations.
   471→%
   472→%  For example a distortion function where    u = U(x,y)   v = V(x,y)
   473→%  And the functions U() and V() have separate coefficents, but are being
   474→%  generated from a common x,y->u,v  data set.
   475→%
   476→%  Another example is generation of a color gradient from a set of colors at
   477→%  specific coordients, such as a list x,y -> r,g,b,a.
   478→%
   479→%  You can also use the 'vectors' to generate an inverse of the given 'matrix'
   480→%  though as a 'column first array' rather than a 'row first array'. For
   481→%  details see http://en.wikipedia.org/wiki/Gauss-Jordan_elimination
   482→%
   483→*/
   484→MagickPrivate MagickBooleanType GaussJordanElimination(double **matrix,
   485→  double **vectors,const size_t rank,const size_t number_vectors)
   486→{
   487→#define GaussJordanSwap(x,y) \
   488→{ \
   489→  if ((x) != (y)) \
   490→    { \
   491→      (x)+=(y); \
   492→      (y)=(x)-(y); \
   493→      (x)=(x)-(y); \
   494→    } \
   495→}
   496→
   497→  double
   498→    max,
   499→    scale;
   500→
   501→  register ssize_t
   502→    i,
   503→    j,
   504→    k;
   505→
   506→  ssize_t
   507→    column,
   508→    *columns,
   509→    *pivots,
   510→    row,
   511→    *rows;
   512→
   513→  columns=(ssize_t *) AcquireQuantumMemory(rank,sizeof(*columns));
   514→  rows=(ssize_t *) AcquireQuantumMemory(rank,sizeof(*rows));
   515→  pivots=(ssize_t *) AcquireQuantumMemory(rank,sizeof(*pivots));
   516→  if ((rows == (ssize_t *) NULL) || (columns == (ssize_t *) NULL) ||
   517→      (pivots == (ssize_t *) NULL))
   518→    {
   519→      if (pivots != (ssize_t *) NULL)
   520→        pivots=(ssize_t *) RelinquishMagickMemory(pivots);
   521→      if (columns != (ssize_t *) NULL)
   522→        columns=(ssize_t *) RelinquishMagickMemory(columns);
   523→      if (rows != (ssize_t *) NULL)
   524→        rows=(ssize_t *) RelinquishMagickMemory(rows);
   525→      return(MagickFalse);
   526→    }
   527→  (void) ResetMagickMemory(columns,0,rank*sizeof(*columns));
   528→  (void) ResetMagickMemory(rows,0,rank*sizeof(*rows));
   529→  (void) ResetMagickMemory(pivots,0,rank*sizeof(*pivots));
   530→  column=0;
   531→  row=0;
   532→  for (i=0; i < (ssize_t) rank; i++)
   533→  {
   534→    max=0.0;
   535→    for (j=0; j < (ssize_t) rank; j++)
   536→      if (pivots[j] != 1)
   537→        {
   538→          for (k=0; k < (ssize_t) rank; k++)
   539→            if (pivots[k] != 0)
   540→              {
   541→                if (pivots[k] > 1)
   542→                  return(MagickFalse);
   543→              }
   544→            else
   545→              if (fabs(matrix[j][k]) >= max)
   546→                {
   547→                  max=fabs(matrix[j][k]);
   548→                  row=j;
   549→                  column=k;
   550→                }
   551→        }
   552→    pivots[column]++;
   553→    if (row != column)
   554→      {
   555→        for (k=0; k < (ssize_t) rank; k++)
   556→          GaussJordanSwap(matrix[row][k],matrix[column][k]);
   557→        for (k=0; k < (ssize_t) number_vectors; k++)
   558→          GaussJordanSwap(vectors[k][row],vectors[k][column]);
   559→      }
   560→    rows[i]=row;
   561→    columns[i]=column;
   562→    if (matrix[column][column] == 0.0)
   563→      return(MagickFalse);  /* sigularity */
   564→    scale=PerceptibleReciprocal(matrix[column][column]);
   565→    matrix[column][column]=1.0;
   566→    for (j=0; j < (ssize_t) rank; j++)
   567→      matrix[column][j]*=scale;
   568→    for (j=0; j < (ssize_t) number_vectors; j++)
   569→      vectors[j][column]*=scale;
   570→    for (j=0; j < (ssize_t) rank; j++)
   571→      if (j != column)
   572→        {
   573→          scale=matrix[j][column];
   574→          matrix[j][column]=0.0;
   575→          for (k=0; k < (ssize_t) rank; k++)
   576→            matrix[j][k]-=scale*matrix[column][k];
   577→          for (k=0; k < (ssize_t) number_vectors; k++)
   578→            vectors[k][j]-=scale*vectors[k][column];
   579→        }
   580→  }
   581→  for (j=(ssize_t) rank-1; j >= 0; j--)
   582→    if (columns[j] != rows[j])
   583→      for (i=0; i < (ssize_t) rank; i++)
   584→        GaussJordanSwap(matrix[i][rows[j]],matrix[i][columns[j]]);
   585→  pivots=(ssize_t *) RelinquishMagickMemory(pivots);
   586→  rows=(ssize_t *) RelinquishMagickMemory(rows);
   587→  columns=(ssize_t *) RelinquishMagickMemory(columns);
   588→  return(MagickTrue);
   589→}
