   591→/*
   592→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   593→%                                                                             %
   594→%                                                                             %
   595→%                                                                             %
   596→%   G e t M a t r i x C o l u m n s                                           %
   597→%                                                                             %
   598→%                                                                             %
   599→%                                                                             %
   600→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   601→%
   602→%  GetMatrixColumns() returns the number of columns in the matrix.
   603→%
   604→%  The format of the GetMatrixColumns method is:
   605→%
   606→%      size_t GetMatrixColumns(const MatrixInfo *matrix_info)
   607→%
   608→%  A description of each parameter follows:
   609→%
   610→%    o matrix_info: the matrix.
   611→%
   612→*/
   613→MagickExport size_t GetMatrixColumns(const MatrixInfo *matrix_info)
   614→{
   615→  assert(matrix_info != (MatrixInfo *) NULL);
   616→  assert(matrix_info->signature == MagickCoreSignature);
