   619→ 
   620→/*
   621→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   622→%                                                                             %
   623→%                                                                             %
   624→%                                                                             %
   625→%   G e t M a t r i x E l e m e n t                                           %
   626→%                                                                             %
   627→%                                                                             %
   628→%                                                                             %
   629→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   630→%
   631→%  GetMatrixElement() returns the specifed element in the matrix.
   632→%
   633→%  The format of the GetMatrixElement method is:
   634→%
   635→%      MagickBooleanType GetMatrixElement(const MatrixInfo *matrix_info,
   636→%        const ssize_t x,const ssize_t y,void *value)
   637→%
   638→%  A description of each parameter follows:
   639→%
   640→%    o matrix_info: the matrix columns.
   641→%
   642→%    o x: the matrix x-offset.
   643→%
   644→%    o y: the matrix y-offset.
   645→%
   646→%    o value: return the matrix element in this buffer.
   647→%
   648→*/
   649→
   650→static inline ssize_t EdgeX(const ssize_t x,const size_t columns)
   651→{
   652→  if (x < 0L)
   653→    return(0L);
   654→  if (x >= (ssize_t) columns)
   655→    return((ssize_t) (columns-1));
   656→  return(x);
   657→}
   658→
   659→static inline ssize_t EdgeY(const ssize_t y,const size_t rows)
   660→{
   661→  if (y < 0L)
   662→    return(0L);
   663→  if (y >= (ssize_t) rows)
   664→    return((ssize_t) (rows-1));
   665→  return(y);
   666→}
   667→
   668→static inline MagickOffsetType ReadMatrixElements(
   669→  const MatrixInfo *magick_restrict matrix_info,const MagickOffsetType offset,
   670→  const MagickSizeType length,unsigned char *magick_restrict buffer)
   671→{
   672→  register MagickOffsetType
   673→    i;
   674→
   675→  ssize_t
   676→    count;
   677→
   678→#if !defined(MAGICKCORE_HAVE_PREAD)
   679→  LockSemaphoreInfo(matrix_info->semaphore);
   680→  if (lseek(matrix_info->file,offset,SEEK_SET) < 0)
   681→    {
   682→      UnlockSemaphoreInfo(matrix_info->semaphore);
   683→      return((MagickOffsetType) -1);
   684→    }
   685→#endif
   686→  count=0;
   687→  for (i=0; i < (MagickOffsetType) length; i+=count)
   688→  {
   689→#if !defined(MAGICKCORE_HAVE_PREAD)
   690→    count=read(matrix_info->file,buffer+i,(size_t) MagickMin(length-i,
   691→      (MagickSizeType) SSIZE_MAX));
   692→#else
   693→    count=pread(matrix_info->file,buffer+i,(size_t) MagickMin(length-i,
   694→      (MagickSizeType) SSIZE_MAX),(off_t) (offset+i));
   695→#endif
   696→    if (count <= 0)
   697→      {
   698→        count=0;
   699→        if (errno != EINTR)
   700→          break;
   701→      }
   702→  }
   703→#if !defined(MAGICKCORE_HAVE_PREAD)
   704→  UnlockSemaphoreInfo(matrix_info->semaphore);
   705→#endif
   706→  return(i);
   707→}
   708→
   709→MagickExport MagickBooleanType GetMatrixElement(const MatrixInfo *matrix_info,
   710→  const ssize_t x,const ssize_t y,void *value)
   711→{
   712→  MagickOffsetType
   713→    count,
   714→    i;
   715→
   716→  assert(matrix_info != (const MatrixInfo *) NULL);
   717→  assert(matrix_info->signature == MagickCoreSignature);
   718→  i=(MagickOffsetType) EdgeY(y,matrix_info->rows)*matrix_info->columns+
   719→    EdgeX(x,matrix_info->columns);
   720→  if (matrix_info->type != DiskCache)
   721→    {
   722→      (void) memcpy(value,(unsigned char *) matrix_info->elements+i*
   723→        matrix_info->stride,matrix_info->stride);
   724→      return(MagickTrue);
   725→    }
   726→  count=ReadMatrixElements(matrix_info,i*matrix_info->stride,
   727→    matrix_info->stride,(unsigned char *) value);
   728→  if (count != (MagickOffsetType) matrix_info->stride)
   729→    return(MagickFalse);
   730→  return(MagickTrue);
   731→}
   732→ 
   733→/*
   734→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   735→%                                                                             %
   736→%                                                                             %
   737→%                                                                             %
   738→%   G e t M a t r i x R o w s                                                 %
   739→%                                                                             %
   740→%                                                                             %
   741→%                                                                             %
   742→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   743→%
   744→%  GetMatrixRows() returns the number of rows in the matrix.
   745→%
   746→%  The format of the GetMatrixRows method is:
   747→%
   748→%      size_t GetMatrixRows(const MatrixInfo *matrix_info)
   749→%
   750→%  A description of each parameter follows:
   751→%
   752→%    o matrix_info: the matrix.
   753→%
   754→*/
   755→MagickExport size_t GetMatrixRows(const MatrixInfo *matrix_info)
   756→{
   757→  assert(matrix_info != (const MatrixInfo *) NULL);
   758→  assert(matrix_info->signature == MagickCoreSignature);
   759→  return(matrix_info->rows);
   760→}
   761→ 
   762→/*
   763→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   764→%                                                                             %
   765→%                                                                             %
   766→%                                                                             %
   767→+   L e a s t S q u a r e s A d d T e r m s                                   %
   768→%                                                                             %
   769→%                                                                             %
   770→%                                                                             %
   771→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   772→%
   773→%  LeastSquaresAddTerms() adds one set of terms and associate results to the
   774→%  given matrix and vectors for solving using least-squares function fitting.
   775→%
   776→%  The format of the AcquireMagickMatrix method is:
   777→%
   778→%      void LeastSquaresAddTerms(double **matrix,double **vectors,
   779→%        const double *terms,const double *results,const size_t rank,
   780→%        const size_t number_vectors);
   781→%
   782→%  A description of each parameter follows:
   783→%
   784→%    o matrix: the square matrix to add given terms/results to.
   785→%
   786→%    o vectors: the result vectors to add terms/results to.
   787→%
   788→%    o terms: the pre-calculated terms (without the unknown coefficent
   789→%             weights) that forms the equation being added.
   790→%
   791→%    o results: the result(s) that should be generated from the given terms
   792→%               weighted by the yet-to-be-solved coefficents.
   793→%
   794→%    o rank: the rank or size of the dimensions of the square matrix.
   795→%            Also the length of vectors, and number of terms being added.
   796→%
   797→%    o number_vectors: Number of result vectors, and number or results being
   798→%      added.  Also represents the number of separable systems of equations
   799→%      that is being solved.
   800→%
   801→%  Example of use...
   802→%
   803→%     2 dimensional Affine Equations (which are separable)
   804→%         c0*x + c2*y + c4*1 => u
   805→%         c1*x + c3*y + c5*1 => v
   806→%
   807→%     double **matrix = AcquireMagickMatrix(3UL,3UL);
   808→%     double **vectors = AcquireMagickMatrix(2UL,3UL);
   809→%     double terms[3], results[2];
   810→%     ...
   811→%     for each given x,y -> u,v
   812→%        terms[0] = x;
   813→%        terms[1] = y;
   814→%        terms[2] = 1;
   815→%        results[0] = u;
   816→%        results[1] = v;
   817→%        LeastSquaresAddTerms(matrix,vectors,terms,results,3UL,2UL);
   818→%     ...
   819→%     if ( GaussJordanElimination(matrix,vectors,3UL,2UL) ) {
   820→%       c0 = vectors[0][0];
   821→%       c2 = vectors[0][1];
   822→%       c4 = vectors[0][2];
   823→%       c1 = vectors[1][0];
   824→%       c3 = vectors[1][1];
   825→%       c5 = vectors[1][2];
   826→%     }
   827→%     else
   828→%       printf("Matrix unsolvable\n);
   829→%     RelinquishMagickMatrix(matrix,3UL);
   830→%     RelinquishMagickMatrix(vectors,2UL);
   831→%
   832→*/
   833→MagickPrivate void LeastSquaresAddTerms(double **matrix,double **vectors,
   834→  const double *terms,const double *results,const size_t rank,
   835→  const size_t number_vectors)
   836→{
   837→  register ssize_t
   838→    i,
   839→    j;
   840→
   841→  for (j=0; j < (ssize_t) rank; j++)
   842→  {
   843→    for (i=0; i < (ssize_t) rank; i++)
   844→      matrix[i][j]+=terms[i]*terms[j];
   845→    for (i=0; i < (ssize_t) number_vectors; i++)
   846→      vectors[i][j]+=results[i]*terms[j];
   847→  }
   848→}
   849→ 
   850→/*
   851→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   852→%                                                                             %
   853→%                                                                             %
   854→%                                                                             %
   855→%   M a t r i x T o I m a g e                                                 %
   856→%                                                                             %
   857→%                                                                             %
   858→%                                                                             %
   859→%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
   860→%
   861→%  MatrixToImage() returns a matrix as an image.  The matrix elements must be
   862→%  of type double otherwise nonsense is returned.
   863→%
   864→%  The format of the MatrixToImage method is:
   865→%
   866→%      Image *MatrixToImage(const MatrixInfo *matrix_info,
   867→%        ExceptionInfo *exception)
   868→%
   869→%  A description of each parameter follows:
   870→%
   871→%    o matrix_info: the matrix.
   872→%
   873→%    o exception: return any errors or warnings in this structure.
   874→%
   875→*/
   876→MagickExport Image *MatrixToImage(const MatrixInfo *matrix_info,
   877→  ExceptionInfo *exception)
   878→{
   879→  CacheView
   880→    *image_view;
   881→
   882→  double
   883→    max_value,
   884→    min_value,
   885→    scale_factor,
   886→    value;
   887→
   888→  Image
   889→    *image;
   890→
   891→  MagickBooleanType
   892→    status;
   893→
   894→  ssize_t
   895→    y;
   896→
   897→  assert(matrix_info != (const MatrixInfo *) NULL);
   898→  assert(matrix_info->signature == MagickCoreSignature);
   899→  assert(exception != (ExceptionInfo *) NULL);
   900→  assert(exception->signature == MagickCoreSignature);
   901→  if (matrix_info->stride < sizeof(double))
   902→    return((Image *) NULL);
   903→  /*
   904→    Determine range of matrix.
   905→  */
   906→  (void) GetMatrixElement(matrix_info,0,0,&value);
   907→  min_value=value;
   908→  max_value=value;
   909→  for (y=0; y < (ssize_t) matrix_info->rows; y++)
   910→  {
   911→    register ssize_t
   912→      x;
   913→
   914→    for (x=0; x < (ssize_t) matrix_info->columns; x++)
   915→    {
   916→      if (GetMatrixElement(matrix_info,x,y,&value) == MagickFalse)
   917→        continue;
   918→      if (value < min_value)
   919→        min_value=value;
   920→      else
   921→        if (value > max_value)
   922→          max_value=value;
   923→    }
   924→  }
   925→  if ((min_value == 0.0) && (max_value == 0.0))
   926→    scale_factor=0;
   927→  else
   928→    if (min_value == max_value)
   929→      {
   930→        scale_factor=(double) QuantumRange/min_value;
   931→        min_value=0;
   932→      }
   933→    else
   934→      scale_factor=(double) QuantumRange/(max_value-min_value);
   935→  /*
   936→    Convert matrix to image.
   937→  */
   938→  image=AcquireImage((ImageInfo *) NULL,exception);
   939→  image->columns=matrix_info->columns;
   940→  image->rows=matrix_info->rows;
   941→  image->colorspace=GRAYColorspace;
   942→  status=MagickTrue;
   943→  image_view=AcquireAuthenticCacheView(image,exception);
   944→#if defined(MAGICKCORE_OPENMP_SUPPORT)
   945→  #pragma omp parallel for schedule(static,4) shared(status) \
   946→    magick_threads(image,image,image->rows,1)
   947→#endif
   948→  for (y=0; y < (ssize_t) image->rows; y++)
   949→  {
   950→    double
   951→      value;
   952→
   953→    register Quantum
   954→      *q;
   955→
   956→    register ssize_t
   957→      x;
   958→
   959→    if (status == MagickFalse)
   960→      continue;
   961→    q=QueueCacheViewAuthenticPixels(image_view,0,y,image->columns,1,exception);
   962→    if (q == (Quantum *) NULL)
   963→      {
   964→        status=MagickFalse;
   965→        continue;
   966→      }
   967→    for (x=0; x < (ssize_t) image->columns; x++)
   968→    {
   969→      if (GetMatrixElement(matrix_info,x,y,&value) == MagickFalse)
   970→        continue;
   971→      value=scale_factor*(value-min_value);
   972→      *q=ClampToQuantum(value);
   973→      q+=GetPixelChannels(image);
   974→    }
   975→    if (SyncCacheViewAuthenticPixels(image_view,exception) == MagickFalse)
   976→      status=MagickFalse;
   977→  }
   978→  image_view=DestroyCacheView(image_view);
   979→  if (status == MagickFalse)
   980→    image=DestroyImage(image);
   981→  return(image);
   982→}
